diff --git a/llvm/lib/Transforms/Vectorize/VPlanRecipes.cpp b/llvm/lib/Transforms/Vectorize/VPlanRecipes.cpp
index a4831ea7c11f..9fd729bca9dd 100644
--- a/llvm/lib/Transforms/Vectorize/VPlanRecipes.cpp
+++ b/llvm/lib/Transforms/Vectorize/VPlanRecipes.cpp
@@ -2888,7 +2888,31 @@ void VPPredInstPHIRecipe::execute(VPTransformState &State) {
   Instruction *ScalarPredInst =
       cast<Instruction>(State.get(getOperand(0), *State.Lane));
   BasicBlock *PredicatedBB = ScalarPredInst->getParent();
-  BasicBlock *PredicatingBB = PredicatedBB->getSinglePredecessor();
+  BasicBlock *PredicatingBB = nullptr;
+  if (BasicBlock *SinglePred = PredicatedBB->getSinglePredecessor()) {
+    PredicatingBB = SinglePred;
+  } else {
+    // Handle multiple predecessors by finding the one that corresponds to
+    // the predicate condition. For now, we'll use a simple heuristic:
+    // look for a predecessor that has a conditional branch leading to this block.
+    for (BasicBlock *Pred : predecessors(PredicatedBB)) {
+      Instruction *TI = Pred->getTerminator();
+      if (BranchInst *BI = dyn_cast<BranchInst>(TI)) {
+        if (BI->isConditional()) {
+          // This predecessor has a conditional branch
+          // Check if this block is one of the targets
+          if (BI->getSuccessor(0) == PredicatedBB || BI->getSuccessor(1) == PredicatedBB) {
+            PredicatingBB = Pred;
+            break;
+          }
+        }
+      }
+    }
+    // If no conditional predecessor found, use the first predecessor as fallback
+    if (!PredicatingBB && !PredicatedBB->predecessors().empty()) {
+      PredicatingBB = *PredicatedBB->pred_begin();
+    }
+  }
   assert(PredicatingBB && "Predicated block has no single predecessor.");
   assert(isa<VPReplicateRecipe>(getOperand(0)) &&
          "operand must be VPReplicateRecipe");
